from __future__ import annotations

REQUIRED_READINESS_CHECKS = (
    "http_accepting_requests",
    "critical_dependencies_reachable",
    "required_migrations_applied",
    "minimal_real_request_served",
)


def missing_readiness_checks(checks: list[str] | tuple[str, ...] | set[str]) -> tuple[str, ...]:
    provided = set(checks)
    return tuple(check for check in REQUIRED_READINESS_CHECKS if check not in provided)


def readiness_contract_is_satisfied(checks: list[str] | tuple[str, ...] | set[str]) -> bool:
    return not missing_readiness_checks(checks)

import unittest

from compose_zero_downtime.health_contract import (
    REQUIRED_READINESS_CHECKS,
    missing_readiness_checks,
    readiness_contract_is_satisfied,
)


class HealthContractTests(unittest.TestCase):
    def test_complete_contract_is_satisfied(self):
        self.assertTrue(readiness_contract_is_satisfied(REQUIRED_READINESS_CHECKS))

    def test_missing_checks_are_reported(self):
        missing = missing_readiness_checks({"http_accepting_requests"})

        self.assertIn("critical_dependencies_reachable", missing)
        self.assertIn("minimal_real_request_served", missing)


if __name__ == "__main__":
    unittest.main()

